<style lang="scss">
	@use '$scss/mixins/bg';

	.opportunity + .opportunity {
		margin-top: 20px;
	}

	.opportunity {
		display: flex;
		align-items: center;
		gap: 15px;

		border: 1px solid #e5e7eb;
		padding: 20px;
		border-radius: 14px;

		h3 {
			margin: 0;
		}

		p {
			margin: 5px 0 0;
			color: var(--text-content-color);
		}

		> div:first-child {
			@include bg.accent;
			border-radius: 10em;
			width: 50px;
			height: 50px;
			display: flex;

			> svg {
				margin: auto;
			}
		}
	}
</style>
